import{s as we,n as fr,d,r as ks,a as O,m as n,i as A,b as a,u as ie,c as u,e as x,f as L,g as _,h as p,t as P,j as y,y as zr,l as pt,o as Rr,p as N,z as mr,k as $r,C as ys,_ as Yr,A as ws,H as Is}from"../chunks/CemWMKdZ.js";import{S as jr,i as Fr,d as xt,t as Me,a as ye,c as Jr,m as _t,b as yt,e as wt,g as Zr}from"../chunks/77OydfSY.js";import{e as K}from"../chunks/D6YF6ztN.js";import{l as Ur}from"../chunks/Cxlo-hov.js";import{B as Kr}from"../chunks/DhAd9Wqk.js";const vr={title:"TVN Bridge — Local-First AI Governance Platform",description:"Enforce constraints AI cannot bypass. Sovereign Firewall, Context Gate, Truth Nodes. 90-97% token savings."},se={heroTagline:"TVN Bridge is a local-first governance platform that enforces constraints AI assistants cannot bypass. Your code. Your rules. Your machine.",features:[{icon:"&#128737;",name:"Sovereign Firewall",description:"3-tier security blocks 30+ destructive operations in <10ms. OWASP LLM06 compliant.",badge:"Proprietary"},{icon:"&#128270;",name:"Context Gate",description:"90-97% token savings, enforced. Forces AI to search before reading. No known prior art.",badge:"Proprietary"},{icon:"&#128220;",name:"Truth Nodes",description:"Human-defined invariants injected into every AI context. AI cannot override them."},{icon:"&#128065;",name:"Universal Audit Trail",description:"Every ALLOW/BLOCK decision logged. Export as JSON/CSV. Know exactly what AI did."},{icon:"&#127968;",name:"Local-First",description:"Zero network calls. Zero telemetry. Your data never leaves your machine."},{icon:"&#128268;",name:"MCP Integration",description:"17 governance tools for Claude, Cursor, Copilot, Gemini, and more. One-click install. Works with any MCP-capable agent."}],stats:[{value:"90-97%",label:"Token Savings"},{value:"&lt;10ms",label:"Firewall Latency"},{value:"1,494",label:"Tests Passing"},{value:"Zero",label:"Telemetry"}],faqs:[{question:"What is TVN Bridge?",answer:"TVN stands for Truth by Verified Node. TVN Bridge is a local-first AI governance platform. It sits between you and your AI coding assistant, enforcing rules the AI cannot bypass — like a firewall for AI behavior. It controls what files AI can access, what operations it can perform, and how much context it consumes."},{question:"Does it send my code to the cloud?",answer:"No. TVN Bridge is 100% local. Zero network calls, zero telemetry, zero data collection. Your code never leaves your machine. The AI assistant you use (like Claude) has its own connection, but TVN Bridge itself phones home to nobody."},{question:"How does it save 90-97% on tokens?",answer:"The Context Gate blocks AI from reading files directly until it searches first. Instead of grepping your entire codebase and dumping thousands of lines into context, the AI is forced to use semantic search to find only the relevant code. The result is dramatically smaller context windows and faster, more accurate responses."},{question:"What AI tools does it work with?",answer:"TVN Bridge integrates with Claude Code, Claude Desktop, Cursor, VS Code / Copilot, Gemini, and Grok via the Model Context Protocol (MCP). It exposes 17 governance tools that enforce rules regardless of which AI agent is calling them. Any CLI tool can also be wrapped via tvn wrap for environment injection and audit trails."},{question:"Is it free?",answer:"TVN Bridge is stewarded by The Rhoades Institute of Technology, a 501(c)(3) nonprofit. We’re committed to making AI governance accessible. Expect a free tier for individuals and fair pricing for teams. Join the waitlist to be the first to know."},{question:"Who is behind this?",answer:"TVN Bridge is built by Johnathon Rhoades and stewarded by The Rhoades Institute of Technology, a 501(c)(3) nonprofit dedicated to transparent, accountable AI tooling. 250,500 lines of code across 9 projects and 7 languages, built by one developer — nights and weekends while working full-time, until January 2026."},{question:'"But you still use cloud AI (Claude, GPT)"',answer:"Yes — TVN acts as a governance filter between you and the API. It controls what data reaches the cloud, blocks sensitive files, and limits token consumption. It’s not anti-cloud. It’s pro-control."},{question:'"95% token savings sounds too good to be true"',answer:"Measured, not estimated. The Context Gate forces AI to search semantically before reading files. Instead of reading 40 files, it reads 3. The math is straightforward."},{question:'"Doesn’t governance slow AI down?"',answer:"The Firewall adds <10ms per decision — invisible. Meanwhile, the Context Gate saves 83% of tool calls, so governed AI is actually faster than ungoverned AI."},{question:'"Won’t AI companies just build this themselves?"',answer:"They profit from more API calls, not fewer. A 95% token reduction is a 95% revenue reduction for them. They won’t build this. TVN’s enforcement layer is designed with a pluggable backend architecture — enforcement engines like Microsoft’s Agent Governance Toolkit and AEGIS can be integrated as components beneath TVN’s knowledge and orchestration layer. We’re the operating system. They’re the drivers."},{question:'"This is just for developers, right?"',answer:"Today, primarily. The architecture is domain-agnostic. We already support code, personal assistant, and tabletop gaming domains. TVN Vault extends the governance model into encrypted database management for anyone. The governance model applies to any AI use case."}],cta:{headline:"Ready to take control?",description:"TVN Bridge is in active development. We’re presenting at CypherCon 2026 (April 1–2, Milwaukee) and Midwest Gaming Classic (April 24–26). Join the waitlist for early access, or find us at the event."},comparison:[{without:"AI reads 40 files to find what it needs",with:"AI searches semantically, reads 3 files"},{without:"31,000+ tokens consumed per question",with:"1,600 tokens consumed per question"},{without:"Redundant reads every session",with:"Persistent memory across sessions"},{without:'AI "forgets" and re-explores constantly',with:"Truth Nodes + Memory Nodes eliminate repetition"},{without:"No audit trail",with:"Every action logged, exportable as JSON/CSV"},{without:"No file write governance",with:"Every write requires human confirmation"}],costSavings:{headline:"95% less waste per interaction",description:"Context Gate eliminates redundant file reads and token consumption. For a team of 5, that translates to ~$2,700/year in reduced API costs.",footnote:"Estimate based on typical Claude API usage at current pricing."},personas:[{title:"Solo Developers",tagline:"Stop burning tokens on files AI doesn't need.",description:"You pay per token. Context Gate cuts that by 90-97%."},{title:"Enterprise Teams",tagline:"Audit trail for every AI action. Export as JSON/CSV.",description:"Compliance teams need proof. TVN provides it automatically."},{title:"Security-Conscious Orgs",tagline:"OWASP LLM06 compliant. Red-team validated.",description:"Firewall blocks 30+ destructive operations in <10ms."},{title:"Multi-Agent Teams",tagline:"One governance layer for Claude, Cursor, Copilot, and more.",description:"Tool name aliases + governance adapters work cross-agent."},{title:"CTOs & Tech Leads",tagline:"Human authority over AI, enforced by architecture.",description:"Truth Nodes + Zero Trust = controllable amplification, not blind trust."}],howItWorks:[{step:1,title:"Install",description:"pip install tvn-bridge"},{step:2,title:"Index Your Project",description:"tvn index — semantic map in seconds"},{step:3,title:"Define Rules",description:"Truth Nodes + Constraints"},{step:4,title:"AI Works Under Governance",description:"Firewall enforces every action"},{step:5,title:"Review",description:"Audit trail — JSON/CSV export"}]},Qr={heroTagline:"TVN Bridge slashes AI compute waste by up to 97%. Local-first governance that protects your codebase and the planet.",features:{0:{description:"Blocks destructive operations in <10ms — preventing costly rollback-and-retry cycles that waste compute and energy."},1:{description:"Cuts token consumption by 90-97%. Less compute per task means less energy per task — at scale, that matters."},2:{description:"Human-defined invariants prevent hallucination-driven rework. Fewer wasted cycles, fewer wasted tokens."},3:{description:"Full ALLOW/BLOCK logging lets you quantify AI compute usage and identify waste patterns across your team."},4:{description:"Runs entirely on your machine. No cloud servers, no data transfer energy costs, no always-on infrastructure."},5:{description:"17 purpose-built governance tools replace brute-force file access across Claude, Cursor, Copilot, and more. Every interaction is scoped — no wasted reads."}},stats:{0:{label:"Less Compute Per Task"},3:{label:"Cloud Infrastructure"}},comparison:{0:{with:"Semantic search reads 3 files — 93% less compute"},1:{with:"1,600 tokens — 95% less energy per question"},4:{with:"Full audit trail — measure your AI energy footprint"},5:{with:"Human confirmation — no costly rollback-and-retry"}},costSavings:{headline:"~95% less compute per task",description:"Less tokens processed = fewer GPU cycles = less energy consumed. At scale, Context Gate turns AI from an energy hog into a precision tool.",footnote:"Based on measured 90-97% token reduction vs ungoverned AI."},personas:{0:{description:"Every token saved is compute not burned. Context Gate saves 90-97%."},1:{description:"Audit trail quantifies AI compute usage — measure your footprint."},2:{description:"Firewall blocks wasteful retries. Fewer cycles, less energy."},3:{description:"One efficient governance layer — no redundant tooling overhead."},4:{description:"Controllable amplification = maximum output, minimum compute."}},extraFaqs:[{question:"How does TVN Bridge reduce AI’s environmental impact?",answer:"Every token an LLM processes requires compute, and compute requires energy. TVN Bridge’s Context Gate reduces token consumption by 90-97% per interaction. The Sovereign Firewall prevents destructive operations that lead to expensive rollback cycles. Together, they dramatically cut the energy cost of AI-assisted development — without sacrificing capability."}],cta:{headline:"Build software without the waste.",description:"Join the waitlist to use AI that respects your codebase and your planet. 90-97% less compute, zero compromise."}},Xr={heroTagline:"TVN Bridge enforces AI boundaries locally — zero telemetry, zero cloud calls, zero data exfiltration. Your code stays yours.",features:{0:{description:"Blocks file exfiltration, unauthorized writes, and destructive ops in <10ms. Your data never goes where you didn’t allow."},1:{description:"AI sees only the code it needs — 90-97% less data exposed per interaction. Data minimization, enforced by architecture."},2:{description:"Define data handling rules as invariants. AI must comply — it cannot override, ignore, or “reinterpret” your policies."},3:{description:"Immutable ALLOW/BLOCK logs provide audit evidence for compliance. Export JSON/CSV for SOC 2, GDPR, or internal review."},4:{description:"No network calls. No telemetry. No analytics. No fingerprinting. Your code, your machine, nobody else."},5:{description:"AI interacts through 17 controlled governance tools across Claude, Cursor, Copilot, and more — every operation is scoped and auditable."}},stats:{0:{label:"Less Data Exposed"},1:{label:"Policy Enforcement"},3:{label:"Data Collection"}},comparison:{0:{with:"Semantic search — AI sees only 3 relevant files"},1:{with:"1,600 tokens — 95% less data exposed per question"},4:{with:"Immutable audit trail — compliance evidence built-in"},5:{with:"Every write requires human confirmation — zero unauthorized access"}},costSavings:{headline:"95% less data exposure per interaction",description:"Context Gate enforces data minimization at the architecture level. AI sees only what it needs — nothing more.",footnote:"Based on measured 90-97% token reduction vs ungoverned AI access."},personas:{0:{description:"Context Gate limits data exposure by 90-97% per interaction."},1:{description:"Immutable logs prove data handling compliance. SOC 2, GDPR ready."},2:{description:"Firewall blocks data exfiltration in <10ms. Nothing gets out."},3:{description:"Controlled access surface across all agents — one policy, everywhere."},4:{description:"Zero Trust architecture — AI sees only what you explicitly allow."}},extraFaqs:[{question:"How does TVN Bridge protect sensitive code?",answer:"TVN Bridge enforces data boundaries at the architecture level, not through trust. The Context Gate ensures AI only sees the minimum code needed (90-97% less exposure). The Sovereign Firewall blocks unauthorized file operations in <10ms. All enforcement runs locally — zero network calls, zero telemetry, zero data collection. Every decision is logged in an immutable audit trail you can export for compliance evidence."}],cta:{headline:"Your code. Nobody else’s.",description:"Join the waitlist for AI governance that proves your data never left your machine. Zero telemetry, full audit trail."}},ea={heroTagline:"TVN Bridge keeps humans in authority over AI actions. Transparent governance with immutable audit trails and rules AI cannot override.",features:{0:{description:"Humans define the boundaries. AI cannot cross them. 30+ operation types governed by rules you set, not rules AI negotiates."},1:{description:"AI gets only the information it needs — nothing more. Proportional access enforced architecturally, not by AI self-restraint."},2:{description:"Encode your team’s values and constraints as invariants. Injected into every AI context — AI must operate within your ethical boundaries."},3:{description:"Every AI decision is logged with full context. Transparent, exportable records that prove AI operated within human-defined boundaries."},4:{description:"You control the entire stack. No external dependencies, no vendor lock-in, no third party with access to your governance data."},5:{description:"AI operates through 17 defined governance tools across Claude, Cursor, Copilot, and more — every capability is explicit and auditable."}},stats:{0:{label:"Context Reduction"},1:{label:"Enforcement Speed"},2:{label:"Governance Tests"},3:{label:"Surveillance"}},comparison:{0:{with:"Forced semantic search — proportional information access"},1:{with:"1,600 tokens — AI gets only what it needs"},4:{with:"Every decision logged — full accountability trail"},5:{with:"Human confirmation required — enforced authority"}},costSavings:{headline:"Accountability at zero cost to capability",description:"Full governance — every action logged, every boundary enforced — with no measurable performance penalty. Doing the right thing shouldn’t require a tradeoff.",footnote:"Firewall adds <10ms latency. Context Gate reduces tool calls by 83%."},personas:{0:{description:"AI operates under rules you define. No unauthorized access."},1:{description:"Every AI decision logged — transparent, accountable, exportable."},2:{description:"Human-defined boundaries AI cannot negotiate or bypass."},3:{description:"Consistent ethical boundaries across every AI tool your team uses."},4:{description:"Governance by design — values encoded at the system level."}},extraFaqs:[{question:"How does TVN Bridge ensure AI stays under human authority?",answer:"TVN Bridge enforces governance at the infrastructure level, not through prompts or AI cooperation. The Sovereign Firewall blocks operations outside human-defined boundaries in <10ms. Truth Nodes inject your values and constraints into every AI context as invariants the AI cannot override. The Universal Audit Trail logs every decision with full context. Humans set the rules; AI cannot negotiate, reinterpret, or bypass them."}],cta:{headline:"AI that answers to you.",description:"Join the waitlist for AI governance built on human authority, transparent rules, and immutable accountability. The way it should be."}},ta={},sa={developer:ta,environmental:Qr,privacy:Xr,ethics:ea}